--
-- Name: log_article_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.log_article_update() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    editor_id INT;
BEGIN
    -- ❗ если изменились только просмотры — не логируем
    IF NEW.title IS NOT DISTINCT FROM OLD.title
       AND NEW.content IS NOT DISTINCT FROM OLD.content
       AND NEW.status IS NOT DISTINCT FROM OLD.status THEN
        RETURN NEW;
    END IF;

    -- берём id пользователя из session variable
    BEGIN
        editor_id := current_setting('myapp.current_user_id')::int;
    EXCEPTION WHEN others THEN
        editor_id := NULL;
    END;

        title,
        content,
        updated_at,
        status,
        views,
        id_article,
        id_user
    )
    VALUES (
        OLD.title,
        OLD.content,
        NOW(),
        OLD.status,
        OLD.views,
        OLD.id,
        editor_id
    );

    RETURN NEW;
END;
$$;


